def solve(s: str) -> str:
    # Check if the string contains any letter
    has_letter = any(c.isalpha() for c in s)

    if has_letter:
        # Swap case for each character if it's a letter, otherwise keep as is
        return ''.join(c.swapcase() if c.isalpha() else c for c in s)
    else:
        # Reverse the entire string if no letters exist
        return s[::-1]

